mapper.select:
select device_type,description,status,update_time,dorm_num,id from repair_order
and status = #{status}
and update_time between #{startTime} and #{endTime}
and dorm_num like concat('%',#{dormNum},'%')
order by case when status = '待处理' then 1 when status = '处理中' then 2 when status = '待确认' then 3 when status = '已完成' then 4 when status = '已取消' then 5 else 6 end , update_time desc

select * from repair_order
and status = #{status}
and update_time between #{startTime} and #{endTime}
and dorm_num like concat('%',#{dormNum},'%')
and student_id = #{studentId}
order by case when status = '待处理' then 1 when status = '处理中' then 2 when status = '待确认' then 3 when status = '已完成' then 4 when status = '已取消' then 5 else 6 end , update_time desc
